'use strict';

/**
 * AssessmentRecommendationBundle — Wave 206d
 *
 * Persists the recommendation bundle generated by the W206 engine
 * whenever a therapist clicks /recommend/accept. Lets the team:
 *
 *   • see the history of suggestions made for a beneficiary
 *   • compare "what the engine proposed" vs "what the therapist
 *     actually accepted" (training signal for future calibration)
 *   • re-open an old bundle to read its rationale without
 *     re-running the engine
 *
 * 90-day TTL — same horizon as the recommendation review cycle
 * specified in care-plan governance. The CarePlan + SmartGoal docs
 * are the long-term record; this is a coaching trail.
 */

const mongoose = require('mongoose');

if (mongoose.models.AssessmentRecommendationBundle) {
  module.exports = mongoose.models.AssessmentRecommendationBundle;
} else {
  const bundleSchema = new mongoose.Schema(
    {
      beneficiary: {
        type: mongoose.Schema.Types.ObjectId,
        ref: 'Beneficiary',
        required: true,
        index: true,
      },
      therapist: {
        type: mongoose.Schema.Types.ObjectId,
        ref: 'Employee',
        default: null,
      },
      branch: {
        type: mongoose.Schema.Types.ObjectId,
        ref: 'Branch',
        default: null,
      },
      // The original inputs the engine consumed (audit trail)
      scoresInput: { type: mongoose.Schema.Types.Mixed, default: null },
      beneficiaryContext: { type: mongoose.Schema.Types.Mixed, default: null },
      // Full bundle snapshot returned by the engine
      bundle: { type: mongoose.Schema.Types.Mixed, required: true },
      // The therapist's selections at accept time
      acceptedGoalCount: { type: Number, default: 0 },
      acceptedProgramCount: { type: Number, default: 0 },
      // Foreign keys to the materialised records
      createdGoalIds: {
        type: [mongoose.Schema.Types.ObjectId],
        ref: 'SmartGoal',
        default: [],
      },
      carePlan: {
        type: mongoose.Schema.Types.ObjectId,
        ref: 'CarePlan',
        default: null,
      },
      // Engine version stamp — lets us re-interpret bundles after
      // a goal-template change (e.g. detect bundles generated under
      // older logic that may now disagree with current engine output)
      engineVersion: { type: String, default: null },
      refinedByLlm: { type: Boolean, default: false },
      overallConfidence: {
        type: String,
        enum: ['high', 'medium', 'needs_therapist_review'],
        default: 'needs_therapist_review',
      },
      // 90-day TTL — Mongo auto-deletes after expiresAt passes
      expiresAt: {
        type: Date,
        default: () => new Date(Date.now() + 90 * 24 * 60 * 60 * 1000),
        index: { expireAfterSeconds: 0 },
      },
    },
    { timestamps: true, collection: 'assessmentrecommendationbundles' }
  );

  bundleSchema.index({ beneficiary: 1, createdAt: -1 });
  bundleSchema.index({ therapist: 1, createdAt: -1 });

  module.exports = mongoose.model('AssessmentRecommendationBundle', bundleSchema);
}
